// src/pages/Home.jsx (updated)
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import api from '../services/api';
import CompanyCard from '../components/companies/CompanyCard';
import Loading from '../components/common/Loading';

const Home = () => {
    const navigate = useNavigate();
    const [searchQuery, setSearchQuery] = useState('');
    const [trendingCompanies, setTrendingCompanies] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchTrendingCompanies();
    }, []);

    const fetchTrendingCompanies = async () => {
        try {
            const { data } = await api.get('/companies/search', {
                params: { limit: 6 }
            });
            setTrendingCompanies(data.companies || []);
        } catch (error) {
            console.error('Failed to fetch trending companies:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchQuery.trim()) {
            navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
        }
    };

    return (
        <div className="home-page">
            <section className="hero-section">
                <div className="container">
                    <motion.h1
                        className="hero-title"
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6 }}
                    >
                        Share Your Experience.
                        <span className="hero-subtitle">Improve Workplaces.</span>
                    </motion.h1>

                    <motion.p
                        className="hero-description"
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6, delay: 0.2 }}
                    >
                        Welp is where employees safely review companies, businesses respond,
                        and psychologists help when needed. Your voice matters.
                    </motion.p>

                    <motion.form
                        onSubmit={handleSearch}
                        className="hero-search"
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6, delay: 0.4 }}
                    >
                        <div className="search-input-wrapper">
                            <input
                                type="text"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Search for companies by name, industry, or location..."
                                className="search-input"
                            />
                            <button type="submit" className="search-button">
                                🔍 Search
                            </button>
                        </div>
                    </motion.form>
                </div>
            </section>

            <section className="features-section">
                <div className="container">
                    <motion.h2
                        className="section-title"
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6 }}
                    >
                        How Welp Works
                    </motion.h2>

                    <div className="features-grid">
                        {[
                            { icon: '📝', title: 'Review Companies', desc: 'Share your work experience anonymously or publicly. Your honest feedback helps others.' },
                            { icon: '💬', title: 'Business Response', desc: 'Companies can reply to reviews and improve their workplace based on feedback.' },
                            { icon: '🤝', title: 'Wellbeing Support', desc: 'Licensed psychologists can offer support when reviews signal distress.' }
                        ].map((feature, index) => (
                            <motion.div
                                key={index}
                                className="feature-card"
                                initial={{ opacity: 0, y: 20 }}
                                whileInView={{ opacity: 1, y: 0 }}
                                viewport={{ once: true }}
                                transition={{ duration: 0.5, delay: index * 0.1 }}
                                whileHover={{ y: -10 }}
                            >
                                <div className="feature-icon">{feature.icon}</div>
                                <h3>{feature.title}</h3>
                                <p>{feature.desc}</p>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </section>

            <section className="trending-section">
                <div className="container">
                    <motion.h2
                        className="section-title"
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6 }}
                    >
                        Trending Companies
                    </motion.h2>

                    {loading ? (
                        <Loading />
                    ) : (
                        <motion.div
                            className="companies-grid"
                            initial={{ opacity: 0 }}
                            whileInView={{ opacity: 1 }}
                            viewport={{ once: true }}
                            transition={{ duration: 0.6, delay: 0.2 }}
                        >
                            {trendingCompanies.map((company, index) => (
                                <motion.div
                                    key={company.id}
                                    initial={{ opacity: 0, y: 20 }}
                                    whileInView={{ opacity: 1, y: 0 }}
                                    viewport={{ once: true }}
                                    transition={{ duration: 0.5, delay: index * 0.1 }}
                                >
                                    <CompanyCard company={company} />
                                </motion.div>
                            ))}
                        </motion.div>
                    )}
                </div>
            </section>

            <section className="cta-section">
                <div className="container">
                    <motion.h2
                        initial={{ opacity: 0, scale: 0.9 }}
                        whileInView={{ opacity: 1, scale: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6 }}
                    >
                        Ready to Share Your Experience?
                    </motion.h2>

                    <motion.p
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6, delay: 0.2 }}
                    >
                        Join thousands of employees making workplaces better,
                        one review at a time.
                    </motion.p>

                    <motion.div
                        className="cta-buttons"
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6, delay: 0.4 }}
                    >
                        <button
                            onClick={() => navigate('/register')}
                            className="btn btn-primary btn-large"
                        >
                            Sign Up Free
                        </button>
                        <button
                            onClick={() => navigate('/login')}
                            className="btn btn-secondary btn-large"
                        >
                            Log In
                        </button>
                    </motion.div>
                </div>
            </section>
        </div>
    );
};

export default Home;