// src/pages/SearchPage.jsx
import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import api from '../services/api';
import CompanyList from '../components/companies/CompanyList';
import CompanySearch from '../components/companies/CompanySearch';

const SearchPage = () => {
    const [searchParams] = useSearchParams();
    const query = searchParams.get('q') || '';
    const [companies, setCompanies] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [pagination, setPagination] = useState({
        page: 1,
        total: 0,
        pages: 0
    });

    useEffect(() => {
        searchCompanies(1);
    }, [query]);

    const searchCompanies = async (page) => {
        setLoading(true);
        setError('');
        try {
            const { data } = await api.get('/companies/search', {
                params: { q: query, page, limit: 12 }
            });
            setCompanies(data.companies || []);
            setPagination(data.pagination || { page: 1, total: 0, pages: 0 });
        } catch (error) {
            setError('Failed to search companies');
            console.error('Search failed:', error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="search-page">
            <div className="container">
                <h1 className="search-title">
                    {query ? `Search results for "${query}"` : 'All Companies'}
                </h1>

                <CompanySearch initialQuery={query} onSearch={searchCompanies} />

                {pagination.total > 0 && (
                    <p className="search-count">
                        Found {pagination.total} companies
                    </p>
                )}

                <CompanyList companies={companies} loading={loading} error={error} />

                {pagination.pages > 1 && (
                    <div className="pagination">
                        <button
                            onClick={() => searchCompanies(pagination.page - 1)}
                            disabled={pagination.page === 1}
                            className="btn btn-secondary"
                        >
                            Previous
                        </button>
                        <span className="page-info">
              Page {pagination.page} of {pagination.pages}
            </span>
                        <button
                            onClick={() => searchCompanies(pagination.page + 1)}
                            disabled={pagination.page === pagination.pages}
                            className="btn btn-secondary"
                        >
                            Next
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default SearchPage;